function updateMrKowalski(node) {
  if (Array.isArray(node)) {
    return node.map(updateMrKowalski);
  }
  if (node && typeof node === 'object') {
    const out = {};
    for (const [k, v] of Object.entries(node)) {
      if (k === 'mr_kowalski') {
        out[k] = 'John Ronald Kowalski';
      } else {
        out[k] = updateMrKowalski(v);
      }
    }
    return out;
  }
  return node;
}

