const widget = await space.current.readWidget("snake-game");
const source = typeof widget === "string" ? widget : (widget?.content ?? widget?.text ?? widget?.code ?? JSON.stringify(widget, null, 2));

const updated = source
  .replace(/setInterval\s*\(\s*updateSnake\s*,\s*\d+\s*\)/g, 'requestAnimationFrame(loop)')
  .replace(/let\s+direction\s*=\s*['"][^'"]+['"]\s*;/, m => `${m}\nlet moveProgress = 0;\nlet lastFrameTime = performance.now();\nlet animationFrame = null;`)
  .replace(/function\s+updateSnake\s*\(\)\s*{/, `function updateSnake() {
  const now = performance.now();
  const dt = Math.min(32, now - lastFrameTime);
  lastFrameTime = now;
  moveProgress = Math.min(1, moveProgress + dt / 120);
  if (moveProgress < 1) return;`)
  .replace(/render\(\);/g, `render(moveProgress);`)
  .replace(/function\s+render\s*\(\s*\)\s*{/, `function render(progress = 1) {`)
  .replace(/const\s+headX\s*=\s*snake\[0\]\.x\s*;\s*const\s+headY\s*=\s*snake\[0\]\.y\s*;/, `const headX = snake[0].x;
  const headY = snake[0].y;
  const prevHeadX = snake[0].prevX ?? headX;
  const prevHeadY = snake[0].prevY ?? headY;
  const lerp = (a, b, t) => a + (b - a) * t;
  const drawHeadX = lerp(prevHeadX, headX, progress);
  const drawHeadY = lerp(prevHeadY, headY, progress);`)
  .replace(/ctx\.fillRect\(\s*headX\s*\*\s*cellSize,\s*headY\s*\*\s*cellSize,\s*cellSize,\s*cellSize\s*\);/, `ctx.fillRect(drawHeadX * cellSize, drawHeadY * cellSize, cellSize, cellSize);`);

return await space.current.patchWidget("snake-game", {
  edits: [
    {
      find: source,
      replace: updated
    }
  ]
})

